/* ─── Slide Registry ─── */
const SLIDES: { id: string; name: string; render: (p: { theme: Theme; copy: Record<string, string>; locale: Locale }) => React.ReactNode }[] = [
  { id: "01-hero", name: "Hero", render: (p) => <Slide1 {...p} /> },
  { id: "02-struggles", name: "Struggles", render: (p) => <Slide2 {...p} /> },
  { id: "03-nudge", name: "Nudge Card", render: (p) => <Slide3 {...p} /> },
  { id: "04-mypath", name: "My Path", render: (p) => <Slide4 {...p} /> },
  { id: "05-widget", name: "Widget", render: (p) => <Slide5 {...p} /> },
  { id: "06-cta", name: "CTA", render: (p) => <Slide6 {...p} /> },
];

/* ─── Main Page ─── */
export default function ScreenshotsPage() {
  const [locale, setLocale] = useState<Locale>("en");
  const [themeId, setThemeId] = useState<ThemeId>("sumi");
  const [sizeIdx, setSizeIdx] = useState(0);
  const [exporting, setExporting] = useState(false);
  const [exportStatus, setExportStatus] = useState("");
  const exportRefs = useRef<(HTMLDivElement | null)[]>([]);

  const theme = THEMES[themeId];
  const copy = COPY[locale];
  const size = IPHONE_SIZES[sizeIdx];

  const doExportSlide = useCallback(async (el: HTMLDivElement, filename: string, w: number, h: number) => {
    el.style.left = "0px";
    el.style.opacity = "1";
    el.style.zIndex = "-1";
    const opts = { width: w, height: h, pixelRatio: 1, cacheBust: true };
    await toPng(el, opts);
    const dataUrl = await toPng(el, opts);
    el.style.left = "-9999px";
    el.style.opacity = "";
    el.style.zIndex = "";
    const link = document.createElement("a");
    link.download = filename;
    link.href = dataUrl;
    link.click();
  }, []);

  const exportCurrent = useCallback(async () => {
    setExporting(true);
    for (let i = 0; i < SLIDES.length; i++) {
      const el = exportRefs.current[i];
      if (!el) continue;
      setExportStatus(`${i + 1}/${SLIDES.length}: ${SLIDES[i].name}`);
      await doExportSlide(el, `${SLIDES[i].id}-${locale}-${themeId}-${size.w}x${size.h}.png`, size.w, size.h);
      await new Promise((r) => setTimeout(r, 400));
    }
    setExportStatus("Done!");
    setExporting(false);
    setTimeout(() => setExportStatus(""), 2000);
  }, [locale, themeId, size, doExportSlide]);

  return (
    <div style={{ minHeight: "100vh", background: "#111", color: "#fff", fontFamily: "Inter, system-ui, sans-serif" }}>
      {/* Toolbar */}
      <div style={{ position: "sticky", top: 0, zIndex: 50, background: "#1a1a1a", borderBottom: "1px solid #333", padding: "12px 24px", display: "flex", gap: 16, alignItems: "center", flexWrap: "wrap" }}>
        <div style={{ display: "flex", gap: 4 }}>
          {LOCALES.map((l) => (
            <button key={l} onClick={() => setLocale(l)} style={{ padding: "6px 16px", borderRadius: 6, border: "none", cursor: "pointer", fontWeight: locale === l ? 700 : 400, background: locale === l ? "#4A90D9" : "#333", color: "#fff", fontSize: 14 }}>
              {l.toUpperCase()}
            </button>
          ))}
        </div>
        <div style={{ display: "flex", gap: 4 }}>
          {(Object.keys(THEMES) as ThemeId[]).map((t) => (
            <button key={t} onClick={() => setThemeId(t)} style={{ padding: "6px 16px", borderRadius: 6, border: "none", cursor: "pointer", fontWeight: themeId === t ? 700 : 400, background: themeId === t ? THEMES[t].accent : "#333", color: "#fff", fontSize: 14 }}>
              {THEMES[t].name}
            </button>
          ))}
        </div>
        <select value={sizeIdx} onChange={(e) => setSizeIdx(Number(e.target.value))} style={{ padding: "6px 12px", borderRadius: 6, background: "#333", color: "#fff", border: "none", fontSize: 14 }}>
          {IPHONE_SIZES.map((s, i) => (
            <option key={i} value={i}>{s.label} ({s.w}x{s.h})</option>
          ))}
        </select>
        <button onClick={exportCurrent} disabled={exporting} style={{ padding: "6px 20px", borderRadius: 6, background: "#4A90D9", color: "#fff", border: "none", cursor: "pointer", fontWeight: 600, fontSize: 14, opacity: exporting ? 0.5 : 1 }}>
          Export {locale.toUpperCase()} {THEMES[themeId].name} (6)
        </button>
        {exportStatus && <span style={{ fontSize: 13, color: "#8BA3C7" }}>{exportStatus}</span>}
      </div>

      {/* Preview Grid */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 20, padding: 24, maxWidth: 1400, margin: "0 auto" }}>
        {SLIDES.map((slide, i) => (
          <div key={slide.id}>
            <div style={{ fontSize: 13, color: "#888", marginBottom: 8 }}>
              {slide.id} — {slide.name}
            </div>
            <div style={{ background: "#222", borderRadius: 12, overflow: "hidden", aspectRatio: `${W}/${H}` }}>
              <div style={{ width: W, height: H, transform: `scale(${1 / 3.3})`, transformOrigin: "top left" }}>
                {slide.render({ theme, copy, locale })}
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Hidden Export Containers */}
      {SLIDES.map((slide, i) => (
        <div
          key={`export-${slide.id}`}
          ref={(el) => { exportRefs.current[i] = el; }}
          style={{ position: "absolute", left: "-9999px", width: size.w, height: size.h }}
        >
          <div style={{ width: W, height: H, transform: `scale(${size.w / W})`, transformOrigin: "top left", fontFamily: "Inter, system-ui, sans-serif" }}>
            {slide.render({ theme, copy, locale })}
          </div>
        </div>
      ))}
    </div>
  );
}
